import java.io.*;
import java.util.*;

class StudentRecord {
    private int id;
    private String name;
    private double gpa;
    private int year;

    StudentRecord(int id, String name, double gpa, int year) {
        this.id = id;
        this.name = name;
        this.gpa = gpa;
        this.year = year;
    }

    @Override
    public String toString() {
        return String.format("ID: %d, Name: %s, GPA: %.2f, Year: %d", 
                           id, name, gpa, year);
    }

    public String toCSV() {
        return id + "," + name + "," + gpa + "," + year;
    }
}

public class CSVExample {
    public static void main(String[] args) {
        // Creating sample data
        List<StudentRecord> students = Arrays.asList(
            new StudentRecord(1, "Alice", 3.75, 2023),
            new StudentRecord(2, "Bob", 3.20, 2024),
            new StudentRecord(3, "Charlie", 3.95, 2023),
            new StudentRecord(4, "Diana", 3.50, 2024)
        );

        // 1. Writing CSV file
        System.out.println("=== Writing CSV ===");
        String csvFile = "students.csv";
        try (BufferedWriter bw = new BufferedWriter(new FileWriter(csvFile))) {
            // Header
            bw.write("ID,Name,GPA,Year");
            bw.newLine();

            // Data
            for (StudentRecord s : students) {
                bw.write(s.toCSV());
                bw.newLine();
            }
            System.out.println("CSV file written: " + csvFile);
        } catch (IOException e) {
            System.out.println("Error writing CSV: " + e.getMessage());
        }

        // 2. Reading CSV file
        System.out.println("=== Reading CSV ===");
        List<StudentRecord> imported = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new FileReader(csvFile))) {
            // Skip header
            String header = br.readLine();
            System.out.println("Header: " + header);

            String line;
            int lineNum = 2;
            while ((line = br.readLine()) != null) {
                // Split by comma
                String[] parts = line.split(",");
                if (parts.length == 4) {
                    try {
                        int id = Integer.parseInt(parts[0].trim());
                        String name = parts[1].trim();
                        double gpa = Double.parseDouble(parts[2].trim());
                        int year = Integer.parseInt(parts[3].trim());

                        StudentRecord record = new StudentRecord(id, name, gpa, year);
                        imported.add(record);
                        System.out.println("Imported: " + record);
                    } catch (NumberFormatException e) {
                        System.out.println("Error parsing line " + lineNum + ": " + e.getMessage());
                    }
                }
                lineNum++;
            }
        } catch (IOException e) {
            System.out.println("Error reading CSV: " + e.getMessage());
        }

        // 3. Complex CSV with quotes
        System.out.println("=== Complex CSV ===");
        // Handle commas and quotes in fields
        String complexCSV = 
            "ID,Name,Description,Course\n" +
            "1,\"Alice, Smith\",\"Loves, programming\",Java\n" +
            "2,\"Bob J.\",\"Good, student\",Python";

        try (BufferedReader br = new BufferedReader(new StringReader(complexCSV))) {
            String header = br.readLine();
            System.out.println("Header: " + header);

            String line;
            while ((line = br.readLine()) != null) {
                // Simple split — doesn't handle quotes properly
                String[] parts = line.split(",");
                System.out.println("Parts: " + Arrays.toString(parts));

                // Better: use a CSV parser library (OpenCSV, etc.)
                // For now, we'll use a simple approach
            }
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }

        // 4. Processing CSV data
        System.out.println("=== Processing ===");
        if (!imported.isEmpty()) {
            double totalGPA = 0;
            for (StudentRecord s : imported) {
                totalGPA += s.gpa;
            }
            double avgGPA = totalGPA / imported.size();
            System.out.println("Average GPA: " + String.format("%.2f", avgGPA));

            // Filter by year
            System.out.println("Students in 2024:");
            for (StudentRecord s : imported) {
                if (s.year == 2024) {
                    System.out.println("  " + s);
                }
            }
        }
    }
}

