import java.io.*;
import java.util.*;

public class CSVPractice {
    public static void main(String[] args) {
        String[] employees = {
            "1,Alice,IT,75000",
            "2,Bob,HR,65000",
            "3,Charlie,IT,82000",
            "4,Diana,Finance,70000"
        };

        // Write CSV
        try (BufferedWriter bw = new BufferedWriter(new FileWriter("employees.csv"))) {
            bw.write("ID,Name,Department,Salary");
            bw.newLine();
            for (String emp : employees) {
                bw.write(emp);
                bw.newLine();
            }
            System.out.println("CSV written!");
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }

        // Read and process CSV
        double totalSalary = 0;
        int count = 0;
        List<String> itEmployees = new ArrayList<>();

        try (BufferedReader br = new BufferedReader(new FileReader("employees.csv"))) {
            String header = br.readLine();  // Skip header
            String line;
            while ((line = br.readLine()) != null) {
                String[] parts = line.split(",");
                if (parts.length == 4) {
                    String name = parts[1];
                    String dept = parts[2];
                    double salary = Double.parseDouble(parts[3]);

                    totalSalary += salary;
                    count++;

                    if (dept.equals("IT")) {
                        itEmployees.add(name);
                    }
                }
            }
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }

        // Results
        if (count > 0) {
            System.out.println("Average salary: $" + String.format("%.2f", totalSalary / count));
            System.out.println("IT Employees: " + itEmployees);
        }
    }
}
